svg.script:
(function() {
  // ── constants ──
  var COLS = 52, ROWS = 7, STEP = 15;
  var GRID_X = 15, GRID_Y = 85;
  var CELL_SIZE = 12;
  var MAX_GHOSTS = 10;
  var GHOST_MOVE_INTERVAL = 1800;
  var ns = 'http://www.w3.org/2000/svg';

  // ── game state ──
  var playerCol = 26;
  var playerRow = 3;
  var score = 0;
  var ghostCount = 0;
  var gameOver = false;
  var ghosts = [];
  var ghostCells = {};

  // ── smooth animation state ──
  var wX, wY, wTX, wTY;  // wizard: current x,y and target x,y

  // ── SVG refs ──
  var svg = document.querySelector('svg');
  var wizard = document.getElementById('wizard');
  var ghostsContainer = document.getElementById('ghosts-container');
  var caughtContainer = document.getElementById('caught-container');
  var scoreText = document.getElementById('score-pill-text');
  var ghostCountText = document.getElementById('ghost-count-pill-text');

  // ── helpers ──
  function cellCenter(col, row) {
    return {
      x: GRID_X + col * STEP + CELL_SIZE / 2,
      y: GRID_Y + row * STEP + CELL_SIZE / 2
    };
  }

  function dist(a, b) { return Math.abs(a - b) > 0.05; }

  // ── move wizard (sets target, game loop lerps there) ──
  function movePlayer(col, row) {
    if (gameOver) return;
    var pos = cellCenter(col, row);
    wTX = pos.x; wTY = pos.y;
    playerCol = col; playerRow = row;
    checkCatchGhost(col, row);
  }

  // ── catch detection ──
  function checkCatchGhost(col, row) {
    for (var i = ghosts.length - 1; i >= 0; i--) {
      var g = ghosts[i];
      if (g.col === col && g.row === row) {
        // Caught!
        score++;
        ghostCount--;
        if (scoreText) scoreText.textContent = '🏆 Score: ' + score;
        if (ghostCountText) ghostCountText.textContent = '👻 Ghosts: ' + ghostCount;

        // Burst
        var pos = cellCenter(col, row);
        var burst = document.createElementNS(ns, 'text');
        burst.setAttribute('x', pos.x);
        burst.setAttribute('y', pos.y);
        burst.setAttribute('text-anchor', 'middle');
        burst.setAttribute('dominant-baseline', 'central');
        burst.setAttribute('font-size', '16');
        burst.textContent = '✨';
        burst.setAttribute('style', 'animation: caught 0.6s ease-out forwards;');
        caughtContainer.appendChild(burst);
        setTimeout(function() { burst.remove(); }, 700);

        // Remove ghost
        if (g.el && g.el.parentNode) g.el.parentNode.removeChild(g.el);
        delete ghostCells[col + ',' + row];
        ghosts.splice(i, 1);
        spawnGhost();
        return;
      }
    }
  }

  // ── create ghost element ──
  function createGhostEl(col, row) {
    var pos = cellCenter(col, row);
    var g = document.createElementNS(ns, 'g');
    g.setAttribute('class', 'ghost-wrapper');
    g.setAttribute('transform', 'translate(' + pos.x + ',' + pos.y + ')');

    var text = document.createElementNS(ns, 'text');
    text.setAttribute('x', 0);
    text.setAttribute('y', 0);
    text.setAttribute('text-anchor', 'middle');
    text.setAttribute('dominant-baseline', 'central');
    text.setAttribute('font-size', '16');
    text.textContent = '👻';
    g.appendChild(text);
    return g;
  }

  // ── spawn ghost ──
  function spawnGhost() {
    if (ghostCount >= MAX_GHOSTS || gameOver) return;
    var attempts = 0, col, row;
    do {
      col = Math.floor(Math.random() * COLS);
      row = Math.floor(Math.random() * ROWS);
      attempts++;
    } while (attempts < 100 &&
      ( (col === playerCol && row === playerRow) ||
        ghostCells[col + ',' + row] ));
    if (attempts >= 100) return;

    var key = col + ',' + row;
    var pos = cellCenter(col, row);
    var el = createGhostEl(col, row);
    ghostsContainer.appendChild(el);
    ghostCells[key] = true;
    ghostCount++;
    if (ghostCountText) ghostCountText.textContent = '👻 Ghosts: ' + ghostCount;
    ghosts.push({
      col: col, row: row, el: el, id: key,
      x: pos.x, y: pos.y,        // current visual position
      tx: pos.x, ty: pos.y       // target position
    });
  }

  // ── move one ghost (target-based, lerped in game loop) ──
  function moveGhost(g) {
    if (!g.el || !g.el.parentNode) return;
    var key = g.col + ',' + g.row;
    delete ghostCells[key];

    var dirs = [[0,-1],[0,1],[-1,0],[1,0]];
    for (var i = dirs.length - 1; i > 0; i--) {
      var j = Math.floor(Math.random() * (i + 1));
      var tmp = dirs[i]; dirs[i] = dirs[j]; dirs[j] = tmp;
    }

    for (var d = 0; d < dirs.length; d++) {
      var nc = g.col + dirs[d][0];
      var nr = g.row + dirs[d][1];
      var nk = nc + ',' + nr;
      if (nc >= 0 && nc < COLS && nr >= 0 && nr < ROWS &&
          !ghostCells[nk] && !(nc === playerCol && nr === playerRow)) {
        g.col = nc; g.row = nr;
        ghostCells[nk] = true;
        g.id = nk;
        var pos = cellCenter(nc, nr);
        g.tx = pos.x; g.ty = pos.y;  // set target → game loop animates
        return;
      }
    }
    ghostCells[g.col + ',' + g.row] = true;
  }

  // ── move all ghosts ──
  function moveAllGhosts() {
    if (gameOver) return;
    var snapshot = ghosts.slice();
    for (var i = 0; i < snapshot.length; i++) {
      moveGhost(snapshot[i]);
      if (snapshot[i].col === playerCol && snapshot[i].row === playerRow)
        checkCatchGhost(playerCol, playerRow);
    }
  }

  // ═══════════════════════════════════════════════════
  //  SMOOTH ANIMATION LOOP (requestAnimationFrame)
  // ═══════════════════════════════════════════════════
  function gameLoop() {
    // ── animate wizard ──
    if (dist(wX, wTX) || dist(wY, wTY)) {
      wX += (wTX - wX) * 0.28;
      wY += (wTY - wY) * 0.28;
      wizard.setAttribute('transform', 'translate(' + wX + ',' + wY + ')');
    }

    // ── animate ghosts ──
    for (var i = 0; i < ghosts.length; i++) {
      var g = ghosts[i];
      if (dist(g.x, g.tx) || dist(g.y, g.ty)) {
        g.x += (g.tx - g.x) * 0.15;
        g.y += (g.ty - g.y) * 0.15;
        g.el.setAttribute('transform', 'translate(' + g.x + ',' + g.y + ')');
      }
    }

    // ── check catch during animation (ghost slides into player) ──
    for (var i = 0; i < ghosts.length; i++) {
      if (ghosts[i].col === playerCol && ghosts[i].row === playerRow) {
        checkCatchGhost(playerCol, playerRow);
        break;
      }
    }

    requestAnimationFrame(gameLoop);
  }

  // ── keyboard handler ──
  function onKey(e) {
    if (gameOver) return;
    var k = e.key;
    var col = playerCol, row = playerRow;
    if (k === 'ArrowUp' || k === 'w' || k === 'W') row--;
    else if (k === 'ArrowDown' || k === 's' || k === 'S') row++;
    else if (k === 'ArrowLeft' || k === 'a' || k === 'A') col--;
    else if (k === 'ArrowRight' || k === 'd' || k === 'D') col++;
    else return;
    e.preventDefault();
    if (col < 0) col = 0;
    if (col >= COLS) col = COLS - 1;
    if (row < 0) row = 0;
    if (row >= ROWS) row = ROWS - 1;
    movePlayer(col, row);
  }

  // ── click-to-move ──
  function onClick(e) {
    if (gameOver) return;
    var t = e.target;
    if (t && t.classList && t.classList.contains('cell')) {
      var id = t.id;
      if (id && id.startsWith('c')) {
        var p = id.substring(1).split('-');
        var col = parseInt(p[0], 10);
        var row = parseInt(p[1], 10);
        if (!isNaN(col) && !isNaN(row)) movePlayer(col, row);
      }
    }
  }

  // ── init ──
  function init() {
    var start = cellCenter(playerCol, playerRow);
    wX = start.x; wY = start.y;
    wTX = start.x; wTY = start.y;
    wizard.setAttribute('transform', 'translate(' + wX + ',' + wY + ')');

    window.addEventListener('keydown', onKey);
    svg.addEventListener('click', onClick);

    // Initial ghosts
    var n = Math.min(MAX_GHOSTS, 4);
    for (var i = 0; i < n; i++) spawnGhost();

    // Start smooth animation loop
    gameLoop();

    // Ghost movement timer
    setInterval(moveAllGhosts, GHOST_MOVE_INTERVAL);

    // Spawn timer
    setInterval(function() {
      if (!gameOver && ghosts.length < MAX_GHOSTS) spawnGhost();
    }, 4000);
  }

  init();
})();
